class Solution {
    public int bitwiseComplement(int n) {
        if (n == 0) return 1;
        int count = 0;
        int m = n;
        while (m != 0) {
            count++;
            m = m >> 1;
        }
        int mask = (1 << count) - 1;
        return n ^ mask;
    }
}
```
